class MyClass:
    def __init__(self, value):
        self._value = value

    @property
    def value(self):
        return self._value

    @value.setter
    def value(self, new_value):
        if not isinstance(new_value, int):
            raise TypeError("Value must be an integer")
        self._value = new_value

    @value.deleter
    def value(self):
        del self._value
